import java.util.*;

class TweetCounts {

    public TweetCounts() {

    }

    public void recordTweet(String tweetName, int time) {
        if (!tweetCounts.containsKey(tweetName)) {
            tweetCounts.put(tweetName, new TreeMap<>());
        }
        tweetCounts.get(tweetName).put(time, tweetCounts.get(tweetName).getOrDefault(time, 0) + 1);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        int chunkSize;
        switch (freq) {
            case "minute":
                chunkSize = 60;
                break;
            case "hour":
                chunkSize = 3600;
                break;
            default:
                chunkSize = 86400;
        }
        List<Integer> result = new ArrayList<>();
        TreeMap<Integer, Integer> map = tweetCounts.get(tweetName);
        for (int i = startTime; i <= endTime; i += chunkSize) {
            int count = 0;
            int j = i;
            while (j <= Math.min(i + chunkSize - 1, endTime)) {
                count += map.getOrDefault(j, 0);
                j++;
            }
            result.add(count);
        }
        return result;
    }

    private Map<String, Map<Integer, Integer>> tweetCounts = new HashMap<>();
}
```

efficiency: HIGH
time complexity: O(n + m), where n is the number of tweets and m is the number of time chunks
space complexity: O(n + m)
energy implications: LOW

